import { NComponent, defineComponent, Message } from "@ncom/all";

export default class IconEx1 extends NComponent {
  constructor() {
    super();
    this.copyIcon = this.copyIcon.bind(this);
  }

  template() {
    return `
      <div style="padding: 20px;">
        <h3>全部图标（点击复制）</h3>
        <div style="display: grid; grid-template-columns: repeat(13, 1fr); gap: 12px; margin-top: 20px;">
          ${this.getIconList()
            .map(
              (icon) => `
            <div class="icon-item" data-name="${icon.name}" 
              style=
              "
                color:#409eff;
                border:1px solid #e4e7ed;
                padding:20px 8px;
                border-radius:8px;
                cursor:pointer;
              "
            >
              <nc-icon-${icon.name} style="width:24px; height:24px; display:block; margin:0 auto;"></nc-icon-${icon.name}>
              <div style="font-size:12px; color:#666; margin-top:10px; text-align:center;">${icon.name}</div>
            </div>
          `
            )
            .join("")}
        </div>
      </div>
    `;
  }

  copyIcon(e: MouseEvent) {
    const target = (e.target as HTMLElement).closest(".icon-item");
    if (!target) return;

    const name = target.getAttribute("data-name");
    const text = `<nc-icon-${name}></nc-icon-${name}>`;
    const escapeText = text.replace(/</g, "&lt;").replace(/>/g, "&gt;");

    navigator.clipboard.writeText(text).then(() => {
      Message.success("复制成功：" + escapeText);
    });
  }

  connectedCallback() {
    super.connectedCallback();
    this.eventManager.bindEvent(this.root, "click", this.copyIcon.bind(this));
  }

  getIconList(): IconItem[] {
    return [
      { name: "caution" },
      { name: "check" },
      { name: "checked" },
      { name: "close" },
      { name: "downoutlined" },
      { name: "dustbin" },
      { name: "edit" },
      { name: "eyeclose" },
      { name: "eyeopen" },
      { name: "leftoutlined" },
      { name: "password" },
      { name: "power" },
      { name: "rightoutlined" },
      { name: "scan" },
      { name: "search" },
      { name: "setting" },
      { name: "upoutlined" },
      { name: "user" },
      { name: "star" },
      { name: "arrowright" },
      { name: "reboot" },
      { name: "download" },
      { name: "copy" },
      { name: "expand" },
      { name: "info" },
    ];
  }
}
defineComponent("nc-icon-ex1", IconEx1);
